import React from "react"
import '../collapse.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick

class Evalulation extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            results: [], teamValue: ""
        };
    }

        componentDidMount() {


            const search = this.props.location.search;
            const params = new URLSearchParams(search);
            const programID = params.get('programid');

            var query = ""
            if (programID != null) {
              query = "?programid=" + programID 
            }

            let headers = new Headers();

            headers.append('Content-Type', 'application/json');
            headers.append('Accept', 'application/json');

            var backUrl = `http://localhost:9000/eval`

            fetch(backUrl, {
                "method": "GET",
                headers: headers
              })
              .then(response => response.json())
              .then(response => {
                //console.log(response);
                this.setState({results: response})
                //_forEach(response, d => console.log(d.name))
                //console.log(this.state.results)
              })
              .catch(err => {
                console.log(err);
              });


          }


          handleDidMount = (arg) => {

            for (let x in this.state.results) {
              var inTomorrow = true
              //content.push(<div>{this.state.results[x].eventDate}</div>)
              //content.push(<div><hr></hr></div>)
              //each team
              for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                        inTomorrow = false
                    }
                  }
              } 
              if (!inTomorrow) {
                var findDate = document.querySelector('[data-date="' + this.state.results[x].eventDate +'"]')
                if (findDate != null) {
                  var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                  for (var i = 0; i < dateNumber.length; i++) {
                    dateNumber[i].style.color = "red"; 
                  }
                }
              }
            }

/*
            for (let x in this.state.results) {
              var inTomorrow = true
              //content.push(<div>{this.state.results[x].eventDate}</div>)
              //content.push(<div><hr></hr></div>)
              //each team
              for (let y in this.state.results[x].data) {
                  if (!this.state.results[x].data[y].inTomorrow) {
                    inTomorrow = false
                  }
                  for (let z in this.state.results[x].data[y].members) {
                    if (!this.state.results[x].data[y].members[z].inTomorrow) {
                        inTomorrow = false
                    }
                  }
              } 
              if (!inTomorrow) {
                console.log(this.state.results[x].eventDate)

                var findDate = document.querySelector('[data-date="' + this.state.results[x].eventDate +'"]')
                var dateNumber = findDate.getElementsByClassName("fc-daygrid-day-number")
                for (var i = 0; i < dateNumber.length; i++) {
                  dateNumber[i].style.color = "red"; 
                }

              }

            }  
*/

          }

          handleEventClick = (arg) => { // bind with an arrow function
            //alert(arg.dateStr)
            console.log(arg)
          }


          handleDateClick = (arg) => { // bind with an arrow function
            //alert(arg.dateStr)
            console.log(arg)
          }


          handleChange = (event) => {
            this.setState({ teamValue: event.target.value });
          };


          render() {


            var todayDate = "Loading ..."
            var content = []
            var events = []

            for (let x in this.state.results) {
                content.push(<div>{this.state.results[x].formatDate}</div>)
                content.push(<div><hr></hr></div>)
                //each team
                for (let y in this.state.results[x].data) {
                    var colorFaculty = "#CCCCCC"
                    if (!this.state.results[x].data[y].inTomorrow) {
                      colorFaculty = "#FF7F7F"
                    }

                    content.push(<div>{this.state.results[x].data[y].assignment + " - " + this.state.results[x].data[y].name}</div>)
                    content.push(<div>&nbsp;</div>)
                    var event2 = []
                    for (let z in this.state.results[x].data[y].members) {
                        var colorRes = "#CCCCCC"
                        if (!this.state.results[x].data[y].members[z].inTomorrow) {
                            colorRes = "#FF7F7F"
                        }
                        //events.push({ title: this.state.results[x].data[y].members[z].name, date: this.state.results[x].eventDate, id: 1, color: "#FF7F7F", textColor: "black" })
                        content.push(<div style={{color: colorRes}}>----- {this.state.results[x].data[y].members[z].name}</div>)
                        content.push(<div>&nbsp;</div>)

                        //overlap
                        var contentWith = "|***| "
                        for (let i in this.state.results[x].data[y].members[z].overlap) {
                            contentWith += "with (" + this.state.results[x].data[y].members[z].overlap[i].name + ") " + this.state.results[x].data[y].members[z].overlap[i].daysTogether + " days |***| "
                        }
                        content.push(<div style={{color: "blue"}}>{contentWith}</div>)
                        content.push(<div>&nbsp;</div>)

                        event2.push({id: this.state.results[x].data[y].members[z].id, groupId: this.state.results[x].groupId,title: "           " + this.state.results[x].data[y].members[z].name,  date: this.state.results[x].eventDate, color: colorRes, textColor: "black" })

                    }

                    if (this.state.teamValue === "" || this.state.teamValue === this.state.results[x].data[y].assignment.replace("M-L Wards Team ", "")) {
                      events.push({id: this.state.results[x].data[y].id, groupId: this.state.results[x].groupId,title: "",  date: this.state.results[x].eventDate, color: "#CCCCCC"})
                      events.push({id: this.state.results[x].data[y].id, groupId: this.state.results[x].groupId,title: this.state.results[x].data[y].assignment.replace("M-L Wards ", "") + " - " + this.state.results[x].data[y].name,  date: this.state.results[x].eventDate, color: colorFaculty, textColor: "black" })
                      var i = 0
                      var id = ""
                      for (let j in event2) {
                        events.push(event2[j])
                        id = event2[j].id
                        i += 1
                      }
                      while (i < 3) {
                        events.push({id: id, groupId: this.state.results[x].groupId,title: " ",  date: this.state.results[x].eventDate, color: "#CCCCCC", textColor: "black" })
                        i += 1
                      }
                    }

                    content.push(<div>***************************************************************************************************************************</div>)
                }

                content.push(<div><hr></hr></div>)


            }

            if (content.length > 0) {
                todayDate = ""
            }





            return (
                <div className="container">
                  <div className="row justify-content-center">
                    <div className="col-md-8" style={{margin: "10px"}}>
                      <h1 className="display-4 text-center">{todayDate}</h1>
                <h3> Team filter:
                      <select id="lang" style={{height: "30px"}} onChange={this.handleChange} value={this.state.teamValue}>
                  <option value="">All Team</option>
                  <option value="A">M-L Wards Team A</option>
                  <option value="B">M-L Wards Team B</option>
                  <option value="C">M-L Wards Team C</option>
                  <option value="D">M-L Wards Team D</option>
                  <option value="E">M-L Wards Team E</option>
                  <option value="F">M-L Wards Team F</option>
                  <option value="G">M-L Wards Team G</option>
                  <option value="H">M-L Wards Team H</option>
               </select>
               </h3>
                      <FullCalendar
        plugins={[ dayGridPlugin, interactionPlugin ]}
        initialView="dayGridMonth"
        events={events}
        eventClick={this.handleEventClick}
        dateClick={this.handleDateClick}
        eventOrder="id"
        eventDidMount={this.handleDidMount}

      />

                    </div>
                  </div>
                </div>
            );
          }


  };

  export default Evalulation
